#!/bin/bash
# SessionStart hook: materialize the private monorepo siblings that the Rust
# crates path-depend on (`../../auth/rust`, `../../bitwise`, `../../gnot`), so a
# standalone web checkout of `gnosis` can resolve them and `cargo` works.
#
# In local monorepo dev these siblings already sit next to `gnosis`, so the hook
# is a no-op outside the remote environment. In a web session it clones each
# sibling through the *same authenticated git proxy* that `origin` uses, so it
# inherits this session's credentials and repository scope. Missing/unauthorized
# siblings only WARN — they never fail session start.
set -euo pipefail

# Web (Claude Code on the web) only; the monorepo already has the siblings.
if [ "${CLAUDE_CODE_REMOTE:-}" != "true" ]; then
  exit 0
fi

PROJECT_DIR="${CLAUDE_PROJECT_DIR:-$(git rev-parse --show-toplevel)}"
PARENT_DIR="$(cd "$PROJECT_DIR/.." && pwd)"

# Derive the authenticated git base from this repo's origin (the session proxy):
#   http://.../git/forkjoin-ai/gnosis  ->  http://.../git/forkjoin-ai/
ORIGIN_URL="$(git -C "$PROJECT_DIR" remote get-url origin)"
BASE_URL="${ORIGIN_URL%/*}/"

# Never hang on an interactive credential prompt — fail the clone fast instead.
export GIT_TERMINAL_PROMPT=0

# External siblings referenced as `../../<name>` by distributed-inference / polyglot.
SIBLINGS=(auth bitwise gnot)

missing=()
for repo in "${SIBLINGS[@]}"; do
  dest="$PARENT_DIR/$repo"
  if [ -d "$dest/.git" ]; then
    echo "[session-start] $repo already present at $dest"
    continue
  fi
  echo "[session-start] cloning $repo -> $dest"
  if git clone --depth 1 "${BASE_URL}${repo}" "$dest"; then
    echo "[session-start] cloned $repo"
  else
    echo "[session-start] WARN: could not clone $repo from ${BASE_URL}${repo}"
    missing+=("$repo")
  fi
done

if [ "${#missing[@]}" -gt 0 ]; then
  echo "[session-start] WARN: unresolved siblings: ${missing[*]}"
  echo "[session-start] Add these repos to this environment's repository scope so the proxy authorizes them; until then the Rust crates that path-depend on them (distributed-inference, polyglot) will not build."
fi

# Optional: warm the cargo registry cache once all siblings resolve, so the
# cached container starts builds faster. Skipped if anything is missing or cargo
# is unavailable. Never fails the hook.
if [ "${#missing[@]}" -eq 0 ] && command -v cargo >/dev/null 2>&1; then
  for manifest in distributed-inference/Cargo.toml polyglot/Cargo.toml; do
    if [ -f "$PROJECT_DIR/$manifest" ]; then
      echo "[session-start] cargo fetch ($manifest)"
      cargo fetch --manifest-path "$PROJECT_DIR/$manifest" >/dev/null 2>&1 \
        || echo "[session-start] WARN: cargo fetch failed for $manifest (continuing)"
    fi
  done
fi

# Optional siblings never block session start.
exit 0
